#!/usr/bin/env bash
# controlnet-decay-risk-low-last-u.sh — 可控生成（ControlNet 控构图/姿态/线稿）(Decay risk: low) last_updated: 2026-06-22 SOP walkthrough for AIGC 创作工作流.
# Auto-generated by cli_writer.py. Source: research/03-workflows.md.
set -euo pipefail
SCRIPT_DIR="$(cd "$(dirname "${BASH_SOURCE[0]}")" && pwd)"
source "${SCRIPT_DIR}/../lib/common.sh"

INDUSTRY="AIGC 创作工作流"
WORKFLOW="可控生成（ControlNet 控构图/姿态/线稿）(Decay risk: low) last_updated: 2026-06-22"

usage() {
  cat <<EOF
controlnet-decay-risk-low-last-u.sh — Walk through "${WORKFLOW}" SOP for ${INDUSTRY}

逐步走完这个工作流的入门 SOP, 然后做失败模式自检, 输出走查报告。

USAGE:
  ./controlnet-decay-risk-low-last-u.sh             # interactive
  ./controlnet-decay-risk-low-last-u.sh --dry-run
  ./controlnet-decay-risk-low-last-u.sh --json
  ./controlnet-decay-risk-low-last-u.sh --explain
  ./controlnet-decay-risk-low-last-u.sh --help
EOF
}

explain() {
  cat <<'EOT'
这个 SOP 走查脚本帮你完成 "可控生成（ControlNet 控构图/姿态/线稿）(Decay risk: low) last_updated: 2026-06-22" 工作流。

一句话: 用垫图经预处理器（openpose/depth/canny/lineart）抽出「结构指令」，约束扩散过程遵循指定构图/姿态/边缘。从「随机抽卡」到「锁结构出图」。

入门 SOP 共 6 步, 失败模式自检 3 项。

相关心智模型:
  • 可控性 ⇄ 抽卡随机（slot machine）的第一性张力: 扩散模型本质是「抽卡机」（Bilawal Sidhu 直接命名 slot machine nature），同 prompt 多跑挑可用——生成式视觉创作的每个决策都在「可控性/工程化复现 ⇄ 随机性/
  • 模型是地板，审美与判断是天花板: 同样的模型与参数，产出天差地别取决于人的审美判断、概念、构图、镜头语言与「在哪一步停」的判断；模型决定下限（地板），人的审美与工程判断决定上限（天花板），「换个更大的底模就行」是外行幻觉。

来源: research/03-workflows.md.
EOT
}

DRY_RUN=0; JSON=0
for arg in "$@"; do
  case "$arg" in
    --help|-h) usage; exit 0 ;;
    --explain) explain; exit 0 ;;
    --dry-run) DRY_RUN=1 ;;
    --json) JSON=1 ;;
  esac
done

declare -a SOP_STEPS=(
  "**准备垫图**：找/拍一张含目标结构的参考图（姿态参考、线稿、深度场景）。"
  "**选预处理器并预处理**：按需求选 —— 人体姿态用 OpenPose、空间结构用 Depth、保边缘用 Canny、线稿用 Lineart/Scribble。必须先跑预处理器把图转成控制图（ControlNet Apply 不会自动转）。(evidence: [T03-S005, T03-S008])"
  "**加载配对 ControlNet 模型**：ControlNetLoader 加载与底模代际匹配的 ControlNet（SDXL 底模配 SDXL ControlNet、Flux 配 Flux ControlNet）。(evidence: [T03-S005])"
  "**接入生成链**：Apply ControlNet 把控制图注入 KSampler 的条件，设 strength（控制权重）。(evidence: [T03-S007])"
  "**调控制权重出图**：从默认权重起，太松结构跑偏、太紧画质僵硬，迭代调到平衡。"
  "**放大精修交付**（同 workflow 1 收尾）。"
)
declare -a FAILURE_MODES=(
  "**预处理器选错**：要锁姿态却用了 Canny（锁的是边缘不是骨架），人物换姿势就跑偏 —— 锁人体动作用 OpenPose、锁空间用 Depth、保轮廓用 Canny，按「要锁什么」选预处理器。"
  "**底模与 ControlNet 代际不配**：SDXL ControlNet 套 Flux 底模静默失效 —— 换底模必须换配对 ControlNet。"
  "**权重一拉到底画质僵死**：strength=1.0 全程生效，结构死板、细节丢 —— 用 start/end percent 让控制只管前段大结构，后段放开补细节。"
)
declare -a STEP_STATUS=()
declare -a STEP_NOTES=()
declare -a FAIL_CHECK=()

ms_section "${INDUSTRY} · ${WORKFLOW} 走查"
ms_info "逐步走完 ${#SOP_STEPS[@]} 步入门 SOP。每步可标 done / skipped / blocked。"
echo

for i in "${!SOP_STEPS[@]}"; do
  ms_section "Step $((i+1))/${#SOP_STEPS[@]}: ${SOP_STEPS[$i]}"
  ms_prompt "状态? [d=done / s=skipped / b=blocked]"
  read -r status
  STEP_STATUS+=("${status:-d}")
  case "${status:-d}" in
    s) ms_prompt "跳过原因 (一句话):"; read -r note ;;
    b) ms_prompt "blocker (一句话):"; read -r note ;;
    *) note="" ;;
  esac
  STEP_NOTES+=("$note")
done

if [[ ${#FAILURE_MODES[@]} -gt 0 ]]; then
  ms_section "失败模式自检"
  for fm in "${FAILURE_MODES[@]}"; do
    if ms_confirm "你是否避免了 — '$fm' ?"; then
      FAIL_CHECK+=("✓ $fm")
    else
      FAIL_CHECK+=("✗ $fm")
    fi
  done
fi

ms_buffer_append "# ${INDUSTRY} — ${WORKFLOW} 走查报告"
ms_buffer_append ""
ms_buffer_append "_生成时间: $(date '+%Y-%m-%d %H:%M:%S')_"
ms_buffer_append ""
ms_buffer_append "## SOP 步骤"
ms_buffer_append ""
for i in "${!SOP_STEPS[@]}"; do
  status_icon="?"
  case "${STEP_STATUS[$i]}" in
    d|D) status_icon="✓" ;;
    s|S) status_icon="↷" ;;
    b|B) status_icon="✗" ;;
  esac
  if [[ -n "${STEP_NOTES[$i]}" ]]; then
    ms_buffer_append "$((i+1)). [${status_icon}] ${SOP_STEPS[$i]} — ${STEP_NOTES[$i]}"
  else
    ms_buffer_append "$((i+1)). [${status_icon}] ${SOP_STEPS[$i]}"
  fi
done
ms_buffer_append ""
if [[ ${#FAIL_CHECK[@]} -gt 0 ]]; then
  ms_buffer_append "## 失败模式自检"
  ms_buffer_append ""
  for line in "${FAIL_CHECK[@]}"; do
    ms_buffer_append "- $line"
  done
  ms_buffer_append ""
fi

if [[ $JSON -eq 1 ]]; then
  ms_emit_json \
    "workflow" "${WORKFLOW}" \
    "step_count" "${#SOP_STEPS[@]}" \
    "failure_check_count" "${#FAILURE_MODES[@]}"
elif [[ $DRY_RUN -eq 1 ]]; then
  ms_emit_md_stdout
else
  ms_emit_md_file "controlnet-decay-risk-low-last-u-walkthrough"
fi
